import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> version
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(pname, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)

changes = []
unchanged = []

all_keys = sorted(set(list(bl.keys()) + list(al.keys())))
for key in all_keys:
    pname, fw, pid = key
    bv = bl.get(key)
    av = al.get(key)
    if bv and av and bv == av:
        unchanged.append((pname, fw, pid, av))
    elif bv and av and bv != av:
        changes.append((pname, fw, pid, bv, av, 'Aligned to highest version'))
    elif bv and not av:
        changes.append((pname, fw, pid, bv, '-', 'Removed'))
    elif not bv and av:
        changes.append((pname, fw, pid, '-', av, 'Added'))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} | {c[1]} | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} | {u[1]} | {u[2]} | {u[3]}')
"

